    pub(super) async fn create_compute_route(
        &self,
        config: &serde_json::Value,
    ) -> Result<ResourceOutput, ProviderError> {
        // Extract fields from config
        let description = config
            .optional_str("/identity/description")
            .map(String::from);
        let dest_range = config.optional_str("/config/dest_range").map(String::from);
        let name = config.require_str("/identity/name")?.to_string();
        let network = config.optional_str("/network/network").map(String::from);
        let next_hop_gateway = config
            .optional_str("/config/next_hop_gateway")
            .map(String::from);
        let next_hop_ilb = config
            .optional_str("/config/next_hop_ilb")
            .map(String::from);
        let next_hop_instance = config
            .optional_str("/config/next_hop_instance")
            .map(String::from);
        let next_hop_ip = config.optional_str("/config/next_hop_ip").map(String::from);
        let next_hop_network = config
            .optional_str("/config/next_hop_network")
            .map(String::from);
        let next_hop_vpn_tunnel = config
            .optional_str("/config/next_hop_vpn_tunnel")
            .map(String::from);
        // TODO: extract params (Nested(RouteParams)) from config["/config/params"]
        let priority = config.optional_i64("/security/priority");
        // TODO: extract tags (Array(String)) from config["/identity/tags"]

        // Build SDK model
        let mut model = google_cloud_compute_v1::model::Route::default();
        if let Some(v) = description {
            model = model.set_description(v);
        }
        if let Some(v) = dest_range {
            model = model.set_dest_range(v);
        }
        model = model.set_name(name.clone());
        if let Some(v) = network {
            model = model.set_network(v);
        }
        if let Some(v) = next_hop_gateway {
            model = model.set_next_hop_gateway(v);
        }
        if let Some(v) = next_hop_ilb {
            model = model.set_next_hop_ilb(v);
        }
        if let Some(v) = next_hop_instance {
            model = model.set_next_hop_instance(v);
        }
        if let Some(v) = next_hop_ip {
            model = model.set_next_hop_ip(v);
        }
        if let Some(v) = next_hop_network {
            model = model.set_next_hop_network(v);
        }
        if let Some(v) = next_hop_vpn_tunnel {
            model = model.set_next_hop_vpn_tunnel(v);
        }
        // TODO: set params on model via .set_params()
        if let Some(v) = priority {
            model = model.set_priority(v as u32);
        }
        // TODO: set tags on model via .set_tags()

        // Make API call
        self.routes()
            .await?
            .insert()
            .set_project(&self.project_id)
            .set_body(model)
            .send()
            .await
            .map_err(|e| super::classify_gcp_error("Insert Route", e))?;

        let provider_id = name.to_string();
        self.read_compute_route(&provider_id).await
    }

    pub(super) async fn read_compute_route(
        &self,
        provider_id: &str,
    ) -> Result<ResourceOutput, ProviderError> {
        let name = provider_id.to_string();
        let route = self
            .routes()
            .await?
            .get()
            .set_project(&self.project_id)
            .set_route(&name)
            .send()
            .await
            .map_err(|e| super::classify_gcp_error("GetRoute", e))?;

        let state = serde_json::json!({
            "identity": {
                "description": route.description.as_deref().unwrap_or(""),
                "name": route.name.as_deref().unwrap_or(""),
                "tags": serde_json::Value::Null /* TODO: tags is complex type */,
            },
            "config": {
                "dest_range": route.dest_range.as_deref().unwrap_or(""),
                "next_hop_gateway": route.next_hop_gateway.as_deref().unwrap_or(""),
                "next_hop_ilb": route.next_hop_ilb.as_deref().unwrap_or(""),
                "next_hop_instance": route.next_hop_instance.as_deref().unwrap_or(""),
                "next_hop_ip": route.next_hop_ip.as_deref().unwrap_or(""),
                "next_hop_network": route.next_hop_network.as_deref().unwrap_or(""),
                "next_hop_vpn_tunnel": route.next_hop_vpn_tunnel.as_deref().unwrap_or(""),
                "params": serde_json::Value::Null /* TODO: params is complex type */,
            },
            "network": {
                "network": route.network.as_deref().unwrap_or(""),
            },
            "security": {
                "priority": route.priority.unwrap_or(0),
            },
        });

        let mut outputs = HashMap::new();
        outputs.insert(
            "self_link".into(),
            serde_json::json!(route.self_link.as_deref().unwrap_or("")),
        );

        Ok(ResourceOutput {
            provider_id: provider_id.to_string(),
            state,
            outputs,
        })
    }

