    pub(super) async fn create_compute_resourcepolicy(
        &self,
        config: &serde_json::Value,
    ) -> Result<ResourceOutput, ProviderError> {
        // Extract fields from config
        let description = config
            .optional_str("/identity/description")
            .map(String::from);
        let name = config.require_str("/identity/name")?.to_string();
        let region = config.optional_str("/sizing/region").map(String::from);
        // TODO: extract workload_policy (Nested(ResourcePolicyWorkloadPolicy)) from config["/config/workload_policy"]

        // Build SDK model
        let mut model = google_cloud_compute_v1::model::ResourcePolicy::default();
        if let Some(v) = description {
            model = model.set_description(v);
        }
        model = model.set_name(name.clone());
        if let Some(v) = region {
            model = model.set_region(v);
        }
        // TODO: set workload_policy on model via .set_workload_policy()

        // Make API call
        let region = config.str_or("/network/region", &self.region).to_string();
        self.resource_policies()
            .await?
            .insert()
            .set_project(&self.project_id)
            .set_region(&region)
            .set_body(model)
            .send()
            .await
            .map_err(|e| super::classify_gcp_error("Insert ResourcePolicy", e))?;

        let provider_id = format!("{region}/{name}");
        self.read_compute_resourcepolicy(&provider_id).await
    }

    pub(super) async fn read_compute_resourcepolicy(
        &self,
        provider_id: &str,
    ) -> Result<ResourceOutput, ProviderError> {
        let (region, name) = super::parse_region_resource(provider_id, &self.region);
        let resource_policy = self
            .resource_policies()
            .await?
            .get()
            .set_project(&self.project_id)
            .set_region(&region)
            .set_resource_policy(&name)
            .send()
            .await
            .map_err(|e| super::classify_gcp_error("GetResourcePolicy", e))?;

        let state = serde_json::json!({
            "identity": {
                "description": resource_policy.description.as_deref().unwrap_or(""),
                "name": resource_policy.name.as_deref().unwrap_or(""),
            },
            "config": {
                "workload_policy": serde_json::Value::Null /* TODO: workload_policy is complex type */,
            },
            "sizing": {
                "region": resource_policy.region.as_deref().unwrap_or(""),
            },
        });

        let mut outputs = HashMap::new();
        outputs.insert(
            "self_link".into(),
            serde_json::json!(resource_policy.self_link.as_deref().unwrap_or("")),
        );

        Ok(ResourceOutput {
            provider_id: provider_id.to_string(),
            state,
            outputs,
        })
    }

    pub(super) async fn update_compute_resourcepolicy(
        &self,
        provider_id: &str,
        config: &serde_json::Value,
    ) -> Result<ResourceOutput, ProviderError> {
        let (region, name) = super::parse_region_resource(provider_id, &self.region);
        // Extract fields from config
        let description = config
            .optional_str("/identity/description")
            .map(String::from);
        // TODO: extract workload_policy (Nested(ResourcePolicyWorkloadPolicy)) from config["/config/workload_policy"]

        let mut model = google_cloud_compute_v1::model::ResourcePolicy::default();
        if let Some(v) = description {
            model = model.set_description(v);
        }
        // TODO: set workload_policy on model via .set_workload_policy()

        self.resource_policies()
            .await?
            .patch()
            .set_project(&self.project_id)
            .set_region(&region)
            .set_resource_policy(&name)
            .set_body(model)
            .send()
            .await
            .map_err(|e| super::classify_gcp_error("patch ResourcePolicy", e))?;

        self.read_compute_resourcepolicy(provider_id).await
    }

    pub(super) async fn delete_compute_resourcepolicy(
        &self,
        provider_id: &str,
    ) -> Result<(), ProviderError> {
        let (region, name) = super::parse_region_resource(provider_id, &self.region);
        self.resource_policies()
            .await?
            .delete()
            .set_project(&self.project_id)
            .set_region(&region)
            .set_resource_policy(&name)
            .send()
            .await
            .map_err(|e| super::classify_gcp_error("DeleteResourcePolicy", e))?;
        Ok(())
    }
